pub async fn reason(
        &self,
        scope_id: &str,
        check: Option<&str>,
    ) -> Result<ReasonResponse> {
        let resp = self
            .client
            .post(format!("{}/v1/reason", self.base_url))
            .json(&ReasonRequest {
                scope_id: scope_id.to_string(),
                check: check.map(String::from),
            })
            .send()
            .await?
            .error_for_status()?;

        Ok(resp.json().await?)
    }
